export type WeatherIconStyle = 'fill' | 'line' | 'monochrome';
export type WeatherIconVariant = 'static' | 'animated';

export type WeatherCode =
  | '01d' | '01n' // clear sky
  | '02d' | '02n' // few clouds
  | '03d' | '03n' // scattered clouds
  | '04d' | '04n' // broken clouds
  | '09d' | '09n' // shower rain
  | '10d' | '10n' // rain
  | '11d' | '11n' // thunderstorm
  | '13d' | '13n' // snow
  | '50d' | '50n'; // mist

// Map OpenWeather codes to icon file names in the weather-icons repository
export const weatherCodeToIconName: Record<WeatherCode, string> = {
  // Clear
  '01d': 'clear-day',
  '01n': 'clear-night',

  // Few clouds
  '02d': 'partly-cloudy-day',
  '02n': 'partly-cloudy-night',

  // Scattered clouds
  '03d': 'cloudy',
  '03n': 'cloudy',

  // Broken clouds
  '04d': 'cloudy',
  '04n': 'cloudy',

  // Shower rain
  '09d': 'rain',
  '09n': 'rain',

  // Rain
  '10d': 'rain',
  '10n': 'rain',

  // Thunderstorm
  '11d': 'thunderstorm',
  '11n': 'thunderstorm',

  // Snow
  '13d': 'snow',
  '13n': 'snow',

  // Mist
  '50d': 'mist',
  '50n': 'mist',
};
